// Список ниш/ключевых слов для поиска
// Редактируй этот список под себя!
const queries = [
  "Finance / Investing Explainers",
  "Dark Geography / Abandoned Places",
  "True Crime / Missing Persons",
  "Science Explainers",
  "Geopolitics / Military Analysis",
  "AI / Future Tech",
  "Space / Astronomy",
  "Psychology / Human Behavior",
  "History Mysteries / Ancient Civilizations",
  "Health & Longevity / Biohacking"
];

const items = queries.map(q => ({ json: { query: q } }));
return items;

// Извлекаем video ID и базовую инфу из результатов поиска
const items = $input.all();
// HTTP-нода "YouTube Search API" заменяет json ответом API,
// поэтому исходный query берём обратно из ноды "Список ниш" по индексу
const originalQueries = $('Список ниш').all();
const results = [];

for (let i = 0; i < items.length; i++) {
	const videos = items[i].json.items || [];
	const query = originalQueries[i]?.json?.query || 'Unknown';

	for (const video of videos) {
		if (video.id && video.id.videoId) {
			results.push({
				json: {
					videoId: video.id.videoId,
					title: video.snippet.title,
					channelTitle: video.snippet.channelTitle,
					channelId: video.snippet.channelId,
					publishedAt: video.snippet.publishedAt,
					thumbnail: video.snippet.thumbnails?.high?.url || video.snippet.thumbnails?.default?.url,
					query
				}
			});
		}
	}
}

return results;

const items = $input.all();

const results = [];

const MAX_AGE_DAYS = 7;
const MIN_VIEWS = 100000;

for (const item of items) {

    const v = item.json;

    if (v.ageDays > MAX_AGE_DAYS)
        continue;

    if (v.viewCount < MIN_VIEWS)
        continue;

    results.push(item);

}

if (!results.length) {

    return [
        {
            json: {
                skip: true
            }
        }
    ];

}

results.sort(
    (a,b)=>b.json.viewsPerHour-a.json.viewsPerHour
);

return results;

// Формируем красивое сообщение для Telegram — для КАЖДОГО видео из инпута
const items = $input.all();

const results = items.map(({ json: item }) => {
	const viewsFormatted = new Intl.NumberFormat('ru-RU').format(item.viewCount);
	const likesFormatted = new Intl.NumberFormat('ru-RU').format(item.likeCount);
	const commentsFormatted = new Intl.NumberFormat('ru-RU').format(item.commentCount);
	const vphFormatted = new Intl.NumberFormat('ru-RU').format(item.viewsPerHour);

	const emoji = item.viewCount > 1000000 ? '🔥🔥🔥' : item.viewCount > 500000 ? '🔥🔥' : '🔥';

	const message = `${emoji} <b>АУТЛАЙЕР НАЙДЕН</b>

📺 <b>${item.title}</b>

👤 Канал: ${item.channelTitle}
🔍 Ниша: ${item.query?.replace(/\s+/g, '_') || 'unknown'}

📊 <b>Статистика:</b>
👁 Просмотры: <b>${viewsFormatted}</b>
❤️ Лайки: ${likesFormatted}
💬 Комментарии: ${commentsFormatted}
⚡️ Просмотров/час: <b>${vphFormatted}</b>
📈 Engagement: ${item.engagementRate}%
🕐 Возраст: ${item.ageDays} дней

🔗 ${item.videoUrl}`;

	return { json: { message, videoUrl: item.videoUrl, title: item.title } };
});

return results;

// Ничего нового — просто логируем
console.log('Нет новых аутлайеров в этом цикле');
return [{ json: { status: 'no_new_outliers', timestamp: new Date().toISOString() } }];

const items = $input.all();

const batchSize = 50;
const batches = [];

for (let i = 0; i < items.length; i += batchSize) {

    const batch = items.slice(i, i + batchSize);

    batches.push({
        json: {
            ids: batch.map(item => item.json.videoId).join(","),
            original: batch.map(item => item.json)
        }
    });

}

return batches;

const batches = $input.all();

const results = [];

for (const batch of batches) {

    const original = batch.json.original || [];

    const videos = batch.json.items || [];

    for (const video of videos) {

        const source = original.find(v => v.videoId === video.id);

        if (!source) continue;

        const snippet = video.snippet || {};
        const stats = video.statistics || {};
        const content = video.contentDetails || {};

        const viewCount = Number(stats.viewCount || 0);
        const likeCount = Number(stats.likeCount || 0);
        const commentCount = Number(stats.commentCount || 0);

        const publishedAt = new Date(snippet.publishedAt);
        const ageHours = (Date.now() - publishedAt) / 3600000;
        const ageDays = ageHours / 24;

        const viewsPerHour = Math.round(
            viewCount / Math.max(ageHours, 1)
        );

        const engagementRate =
            viewCount > 0
                ? Number((((likeCount + commentCount) / viewCount) * 100).toFixed(2))
                : 0;

        results.push({
            json: {

                videoId: video.id,

                title: snippet.title,

                channelTitle: snippet.channelTitle,

                channelId: snippet.channelId,

                publishedAt: snippet.publishedAt,

                ageDays: Number(ageDays.toFixed(1)),

                ageHours: Math.round(ageHours),

                viewCount,

                likeCount,

                commentCount,

                viewsPerHour,

                engagementRate,

                duration: content.duration,

                thumbnail:
                    snippet.thumbnails?.high?.url ||
                    snippet.thumbnails?.medium?.url ||
                    snippet.thumbnails?.default?.url ||
                    "",

                videoUrl:
                    `https://youtube.com/watch?v=${video.id}`,

                query: source.query || "Unknown"

            }
        });

    }

}

return results;

// Проверяем, отправлялось ли уже это видео
// Используем встроенное хранилище n8n (workflow static data),
// а не файловую систему — так надёжнее (работает и в облаке n8n,
// и переживает перезапуск контейнера).
const staticData = $getWorkflowStaticData('global');
if (!staticData.sentVideos) staticData.sentVideos = {};

const items = $input.all();
const newItems = [];

// Удаляем записи старше 30 дней, чтобы объект не рос бесконечно
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
for (const id of Object.keys(staticData.sentVideos)) {
	if (staticData.sentVideos[id] < thirtyDaysAgo) {
		delete staticData.sentVideos[id];
	}
}

// Оставляем только новые видео
for (const item of items) {
	const videoId = item.json.videoId;
	if (!staticData.sentVideos[videoId]) {
		newItems.push(item);
		staticData.sentVideos[videoId] = Date.now();
	}
}

// Если новых видео нет — явно возвращаем skip,
// чтобы нода "Новые видео?" могла это отследить
if (newItems.length === 0) {
	return [{ json: { skip: true } }];
}

return newItems;
